mapper.select:
SELECT * FROM ( SELECT m.message_id AS messageId, m.room_id AS roomId, m.sender_account_id AS senderAccountId, d.nickname, d.handle, d.role_type AS roleType, d.profile_image_url AS profileImageUrl, m.is_deleted AS isDeleted, TO_CHAR(m.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, m.content AS content,
ROW_NUMBER() OVER( ORDER BY
m.created_at ASC m.created_at DESC
) AS rn
FROM chat_messages m JOIN vw_account_display d ON m.sender_account_id = d.account_id
) WHERE rn > ( (#{page} - 1) * #{size} ) AND rn <= ( #{page} * #{size} )

mapper.update:
UPDATE chat_messages
SET is_deleted = 'Y'
WHERE message_id = #{messageId}
